public partial class NodeView : UserControl
{
    private Point _lastPoint;
    private bool _isDragging;
    private Canvas? _parentCanvas;

    public NodeView()
    {
        InitializeComponent();

        AttachedToVisualTree += (_, _) =>
        {
            // Find the first ancestor Canvas in the visual tree
            _parentCanvas = this.GetVisualAncestors().OfType<Canvas>().FirstOrDefault();
        };
    }

    private void OnPointerPressed(object? sender, PointerPressedEventArgs e)
    {
        if (_parentCanvas == null)
            return;

        _lastPoint = e.GetPosition(_parentCanvas);
        _isDragging = true;
        e.Pointer.Capture(sender as IInputElement);
    }

    private void OnPointerMoved(object? sender, PointerEventArgs e)
    {
        if (!_isDragging || _parentCanvas == null || DataContext is not IWorkflowNodeViewModel node)
            return;

        var current = e.GetPosition(_parentCanvas);
        var offset = new Offset(current.X - _lastPoint.X, current.Y - _lastPoint.Y);

        node.MoveCommand.Execute(offset);
        _lastPoint = current;
    }

    private void OnPointerReleased(object? sender, PointerReleasedEventArgs e)
    {
        _isDragging = false;
        e.Pointer.Capture(null);
    }

    private void OnPointerCaptureLost(object? sender, PointerCaptureLostEventArgs e)
    {
        _isDragging = false;
    }
}

