private void SyncSlotLayouts()
{
    // Synchronize the layout of input and output slots for the current node.
    if (DataContext is not ViewModels.NodeViewModel node)
        return;

    SyncSlot(PART_InputSlot, node.InputSlot, node);
    SyncSlot(PART_OutputSlot, node.OutputSlot, node);
}

private void SyncSlot(Control? control, IWorkflowSlotViewModel? slot, IWorkflowNodeViewModel node)
{
    // Skip if any required object is null or the canvas is not available.
    if (control is null || slot is null || _parentCanvas is null)
        return;

    // Skip if the control has no valid size.
    if (control.Bounds.Width <= 0 || control.Bounds.Height <= 0)
        return;

    // Calculate the center point of the control relative to the parent canvas.
    var center = control.TranslatePoint(
        new Point(control.Bounds.Width / 2, control.Bounds.Height / 2),
        _parentCanvas);

    if (center is null)
        return;

    // Retrieve the actual scroll/pan offset applied to the layout.
    var actualOffset = (node.Parent as ViewModels.TreeViewModel)?.Layout.ActualOffset;

    // Update the slot's anchor position, adjusting for layout offset.
    slot.Anchor = new Anchor(
        center.Value.X - (actualOffset?.Horizontal ?? 0),
        center.Value.Y - (actualOffset?.Vertical ?? 0),
        slot.Anchor.Layer);
}

private void OnPointerReleased(object sender, PointerReleasedEventArgs e)
{
    if (DataContext is not IWorkflowSlotViewModel slot) return;

    slot.ReceiveConnectionCommand.Execute(null);
}

private void OnPointerPressed(object sender, PointerPressedEventArgs e)
{
    if (DataContext is not IWorkflowSlotViewModel slot) return;

    slot.SendConnectionCommand.Execute(null);

    // Note: Depending on the specific GUI framework, handle event bubbling and other mechanisms that affect event propagation.
    e.Pointer.Capture(null);
}

